<body>
<div class="container" id="mainApp">
    <header>
        <h1><i class="fas fa-users"></i> 湾泥渡村 · 手机版</h1>
        <p><span id="userDisplay">离线模式</span></p>
    </header>

    <!-- 统计卡片 -->
    <div class="stats-section">
        <div class="stats-row" id="stats-row"></div>
        <div class="stats-actions">
            <button class="btn-warning" id="group-stats-btn"><i class="fas fa-table"></i> 各组统计</button>
            <button class="btn-info" id="chart-btn"><i class="fas fa-chart-bar"></i> 图表</button>
        </div>
    </div>

    <!-- 搜索 -->
    <section class="search-section">
        <div class="search-controls">
            <div class="search-type-selector">
                <label>全局搜索</label>
                <div class="search-input-group">
                    <input type="text" id="search-input" placeholder="姓名、电话、地址、身份证...">
                    <button class="btn-primary" id="search-btn"><i class="fas fa-search"></i> 查询</button>
                    <button class="btn-info" id="advanced-search-btn"><i class="fas fa-filter"></i> 高级</button>
                </div>
            </div>
        </div>
        <!-- 搜索工具行：不显示死亡人员 + 快捷操作 -->
        <div class="search-tools">
            <label class="hide-deceased-wrapper" id="hideDeceasedWrapper" title="勾选后隐藏已死亡人员">
                <input type="checkbox" id="hideDeceasedCheckbox">
                <span class="label-text">不显示死亡人员</span>
            </label>
            <button class="btn-secondary" id="reset-btn"><i class="fas fa-redo"></i> 重置</button>
            <button class="btn-success" id="add-btn"><i class="fas fa-user-plus"></i> 添加</button>
            <button class="btn-info" id="export-data-btn"><i class="fas fa-file-export"></i> 导出数据</button>
            <button class="btn-info" id="import-data-btn"><i class="fas fa-file-import"></i> 导入数据</button>
            <button class="btn-danger" id="batch-delete-btn"><i class="fas fa-trash-alt"></i> 批量删除</button>
        </div>
    </section>

    <!-- 批量工具栏 -->
    <div class="batch-toolbar" id="batch-toolbar">
        <div class="batch-info"><span><i class="fas fa-check-circle"></i> 已选择 <span id="selected-count">0</span> 项</span>
            <button class="btn-warning" id="batch-edit-btn"><i class="fas fa-edit"></i> 批量修改</button>
            <button class="btn-danger" id="confirm-batch-delete"><i class="fas fa-trash-alt"></i> 确认删除</button>
            <button class="btn-secondary" id="cancel-batch"><i class="fas fa-times"></i> 取消</button>
        </div>
    </div>

    <div class="data-count" id="data-count">加载中...</div>
    <div class="table-controls">
        <div class="table-pagination-top" id="table-pagination-top"></div>
        <div class="page-size-selector">
            <label>每页：</label>
            <select id="items-per-page-top">
                <option value="10">10</option>
                <option value="20" selected>20</option>
                <option value="50">50</option>
                <option value="100">100</option>
            </select>
        </div>
    </div>

    <table id="villagers-table">
        <thead><tr><th class="table-checkbox-column"></th><th>姓名</th><th>性别</th><th class="age-column">年龄</th><th>户籍地址</th><th>与户主关系</th><th>电话</th><th>操作</th></tr></thead>
        <tbody id="table-body"></tbody>
    </table>

    <div class="pagination-section">
        <div class="pagination" id="pagination"></div>
        <div class="page-size-selector">
            <label>每页：</label>
            <select id="items-per-page-bottom">
                <option value="10">10</option>
                <option value="20" selected>20</option>
                <option value="50">50</option>
                <option value="100">100</option>
            </select>
        </div>
    </div>
</div>

<!-- ===== 所有模态框 ===== -->
<div id="edit-modal" class="modal"><div class="modal-content"><div class="modal-header"><h2 id="modal-title">添加新村民</h2><span class="close" id="close-modal">&times;</span></div><form id="villager-form"><div class="form-row"><div class="form-group"><label>姓名 *</label><input type="text" id="form-name" required></div><div class="form-group"><label>性别 *</label><select id="form-gender" required><option value="">请选择</option><option value="男">男</option><option value="女">女</option></select></div></div><div class="form-row"><div class="form-group"><label>身份证号 *</label><input type="text" id="form-id" required></div><div class="form-group"><label>户籍地址 *</label><input type="text" id="form-address" required placeholder="如：湾泥渡村10组10号"></div></div><div class="form-row"><div class="form-group"><label>与户主关系 *</label><select id="form-relation" required><option value="">请选择</option><option value="户主">户主</option><option value="妻">妻</option><option value="夫">夫</option><option value="子">子</option><option value="女">女</option><option value="儿媳">儿媳</option><option value="女婿">女婿</option><option value="孙子">孙子</option><option value="孙女">孙女</option><option value="母亲">母亲</option><option value="父亲">父亲</option><option value="弟">弟</option><option value="妹">妹</option><option value="养女">养女</option><option value="非亲属">非亲属</option><option value="其他">其他</option><option value="独立">独立（无户）</option></select></div><div class="form-group"><label>电话</label><input type="text" id="form-phone"></div></div><div class="form-row"><div class="form-group"><label>备注一</label><textarea id="form-note1" rows="2"></textarea></div><div class="form-group"><label>备注二</label><textarea id="form-note2" rows="2"></textarea></div></div><div class="form-row"><div class="form-group"><label>特殊身份</label><div style="display:flex; flex-wrap:wrap; gap:10px;"><label><input type="checkbox" name="tags" value="党员"> 党员</label><label><input type="checkbox" name="tags" value="低保户"> 低保户</label><label><input type="checkbox" name="tags" value="特困供养"> 特困供养</label><label><input type="checkbox" name="tags" value="残疾人"> 残疾人</label><label><input type="checkbox" name="tags" value="退役军人"> 退役军人</label><label><input type="checkbox" name="tags" value="优抚对象"> 优抚对象</label><label><input type="checkbox" name="tags" value="脱贫户"> 脱贫户</label><label><input type="checkbox" name="tags" value="监测户"> 监测户</label><label><input type="checkbox" name="tags" value="吸毒人员"> 吸毒人员</label><label><input type="checkbox" name="tags" value="社区矫正"> 社区矫正</label><label><input type="checkbox" name="tags" value="重点关注"> 重点关注</label><label><input type="checkbox" name="tags" value="留守儿童"> 留守儿童</label><label><input type="checkbox" name="tags" value="独居老人"> 独居老人</label></div></div></div><input type="hidden" id="form-index"><div style="margin-top:30px; display:flex; gap:15px;"><button type="submit" class="btn-success"><i class="fas fa-save"></i> 保存</button><button type="button" class="btn-secondary" id="cancel-edit"><i class="fas fa-times"></i> 取消</button></div></form></div></div>

<div id="detail-modal" class="modal"><div class="modal-content"><div class="modal-header"><h2 id="detail-title">村民详细信息</h2><span class="close" id="close-detail">&times;</span></div><div id="detail-content"></div><div class="detail-actions" id="detail-actions"><button class="btn-primary" id="edit-detail-btn"><i class="fas fa-edit"></i> 编辑</button><button class="btn-danger" id="delete-detail-btn"><i class="fas fa-trash-alt"></i> 删除</button><button class="btn-info" id="print-detail-btn"><i class="fas fa-print"></i> 打印</button><button class="btn-secondary" id="close-detail-btn"><i class="fas fa-times"></i> 关闭</button></div></div></div>

<div id="delete-modal" class="modal"><div class="modal-content warning-dialog"><div class="warning-icon">⚠️</div><h2>确认删除</h2><div class="warning-text"><p>您确定要删除 <strong id="delete-name"></strong> 吗？</p><p>此操作无法撤销！</p></div><div class="warning-actions"><button class="btn-danger" id="confirm-delete"><i class="fas fa-trash-alt"></i> 确认删除</button><button class="btn-secondary" id="cancel-delete"><i class="fas fa-times"></i> 取消</button></div><input type="hidden" id="delete-index"></div></div>

