<script>
// ============================================================
// 1. 初始化 SQLite 数据库（使用 sql.js）
// ============================================================
let db = null;
let SQL = null;
const SQL_JS_URL = 'https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.11.0/sql-wasm.js';

function initSQL() {
    return new Promise((resolve, reject) => {
        if (typeof SQLite !== 'undefined') {
            SQLite({
                locateFile: filename => 'https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.11.0/' + filename
            }).then(_SQL => {
                SQL = _SQL;
                const saved = localStorage.getItem('villager_db');
                let data = null;
                if (saved) {
                    try {
                        const uint8 = new Uint8Array(saved.split(',').map(Number));
                        data = uint8;
                    } catch(e) {}
                }
                if (data) {
                    db = new SQL.Database(data);
                } else {
                    db = new SQL.Database();
                    initTables();
                }
                saveDB();
                resolve();
            }).catch(reject);
        } else {
            const script = document.createElement('script');
            script.src = SQL_JS_URL;
            script.onload = () => {
                initSQL().then(resolve).catch(reject);
            };
            script.onerror = reject;
            document.head.appendChild(script);
        }
    });
}

function initTables() {
    db.run(`
        CREATE TABLE IF NOT EXISTS villagers (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            姓名 TEXT,
            性别 TEXT,
            公民身份证号码 TEXT UNIQUE,
            户籍地址 TEXT,
            与户主关系 TEXT,
            电话号码 TEXT,
            备注一 TEXT,
            备注二 TEXT,
            tags TEXT,
            deleted_at TEXT
        )
    `);
    db.run(`
        CREATE TABLE IF NOT EXISTS villager_photos (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            villager_id INTEGER,
            filename TEXT,
            filepath TEXT,
            description TEXT,
            image_data TEXT,
            uploaded_by INTEGER,
            created_at TEXT
        )
    `);
    db.run(`
        CREATE TABLE IF NOT EXISTS kinship (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            person1_id INTEGER,
            person2_id INTEGER,
            relation TEXT,
            auto INTEGER DEFAULT 0,
            created_at TEXT
        )
    `);
}

function saveDB() {
    if (!db) return;
    const data = db.export();
    const arr = Array.from(data);
    localStorage.setItem('villager_db', arr.join(','));
}

function withDB(callback) {
    if (!db) { console.error('数据库未初始化'); return; }
    const result = callback(db);
    saveDB();
    return result;
}

// ============================================================
// 2. 本地数据库操作函数
// ============================================================
const localDB = {
    getVillagers() {
        return withDB(db => {
            const stmt = db.prepare(`SELECT * FROM villagers WHERE deleted_at IS NULL ORDER BY 户籍地址, 
                CASE 与户主关系 WHEN '户主' THEN 0 WHEN '妻' THEN 1 WHEN '夫' THEN 1 WHEN '子' THEN 2 WHEN '女' THEN 2 WHEN '儿媳' THEN 2 WHEN '女婿' THEN 2 WHEN '孙子' THEN 3 WHEN '孙女' THEN 3 WHEN '母亲' THEN 4 WHEN '父亲' THEN 4 WHEN '弟' THEN 5 WHEN '妹' THEN 5 ELSE 6 END`);
            const result = [];
            while (stmt.step()) {
                result.push(stmt.getAsObject());
            }
            stmt.free();
            return result;
        });
    },
    addVillager(data) {
        return withDB(db => {
            const stmt = db.prepare(`INSERT INTO villagers (姓名, 性别, 公民身份证号码, 户籍地址, 与户主关系, 电话号码, 备注一, 备注二, tags, deleted_at) 
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, NULL)`);
            stmt.run([data.姓名, data.性别, data.公民身份证号码, data.户籍地址, data.与户主关系, data.电话号码, data.备注一, data.备注二, data.tags || '']);
            stmt.free();
            return db.exec('SELECT last_insert_rowid()')[0].values[0][0];
        });
    },
    updateVillager(id, data) {
        return withDB(db => {
            const stmt = db.prepare(`UPDATE villagers SET 姓名=?, 性别=?, 公民身份证号码=?, 户籍地址=?, 与户主关系=?, 电话号码=?, 备注一=?, 备注二=?, tags=? WHERE id=?`);
            stmt.run([data.姓名, data.性别, data.公民身份证号码, data.户籍地址, data.与户主关系, data.电话号码, data.备注一, data.备注二, data.tags || '', id]);
            stmt.free();
        });
    },
    deleteVillager(id) {
        return withDB(db => {
            const stmt = db.prepare(`UPDATE villagers SET deleted_at = datetime('now') WHERE id=?`);
            stmt.run([id]);
            stmt.free();
        });
    },
    getPhotos(villagerId) {
        return withDB(db => {
            const stmt = db.prepare(`SELECT * FROM villager_photos WHERE villager_id = ? ORDER BY created_at DESC`);
            stmt.bind([villagerId]);
            const result = [];
            while (stmt.step()) {
                result.push(stmt.getAsObject());
            }
            stmt.free();
            return result;
        });
    },
    addPhoto(villagerId, filename, imageData, description = '') {
        return withDB(db => {
            const stmt = db.prepare(`INSERT INTO villager_photos (villager_id, filename, filepath, description, image_data, created_at) 
                VALUES (?, ?, ?, ?, ?, datetime('now'))`);
            stmt.run([villagerId, filename, filename, description, imageData]);
            stmt.free();
            return db.exec('SELECT last_insert_rowid()')[0].values[0][0];
        });
    },
    deletePhoto(photoId) {
        return withDB(db => {
            const stmt = db.prepare(`DELETE FROM villager_photos WHERE id=?`);
            stmt.run([photoId]);
            stmt.free();
        });
    },
    updatePhotoDescription(photoId, description) {
        return withDB(db => {
            const stmt = db.prepare(`UPDATE villager_photos SET description=? WHERE id=?`);
            stmt.run([description, photoId]);
            stmt.free();
        });
    },
    getKinship(villagerId) {
        return withDB(db => {
            const stmt = db.prepare(`SELECT k.id, k.person2_id, k.relation, v.姓名 as name 
                FROM kinship k JOIN villagers v ON k.person2_id = v.id 
                WHERE k.person1_id = ? AND v.deleted_at IS NULL ORDER BY k.id`);
            stmt.bind([villagerId]);
            const result = [];
            while (stmt.step()) {
                result.push(stmt.getAsObject());
            }
            stmt.free();
            return result;
        });
    },
    addKinship(person1_id, person2_id, relation) {
        return withDB(db => {
            const check = db.prepare(`SELECT id FROM kinship WHERE person1_id=? AND person2_id=? AND relation=?`);
            check.bind([person1_id, person2_id, relation]);
            if (check.step()) { check.free(); throw new Error('该关系已存在'); }
            check.free();
            const stmt = db.prepare(`INSERT INTO kinship (person1_id, person2_id, relation, auto, created_at) VALUES (?, ?, ?, 0, datetime('now'))`);
            stmt.run([person1_id, person2_id, relation]);
            stmt.free();
        });
    },
    deleteKinship(id) {
        return withDB(db => {
            const stmt = db.prepare(`DELETE FROM kinship WHERE id=?`);
            stmt.run([id]);
            stmt.free();
        });
    },
    exportAll() {
        return withDB(db => {
            const villagers = db.exec('SELECT * FROM villagers WHERE deleted_at IS NULL')[0]?.values || [];
            const photos = db.exec('SELECT * FROM villager_photos')[0]?.values || [];
            const kinship = db.exec('SELECT * FROM kinship')[0]?.values || [];
            return { version: '1.0', exported_at: new Date().toISOString(), data: { villagers, photos, kinship } };
        });
    },
    importData(data, mode = 'append') {
        return withDB(db => {
            if (mode === 'replace') {
                db.exec('DELETE FROM villagers');
                db.exec('DELETE FROM villager_photos');
                db.exec('DELETE FROM kinship');
            }
            const villagers = data.villagers || [];
            const photos = data.photos || [];
            const kinship = data.kinship || [];

            const insertVillager = db.prepare(`INSERT OR IGNORE INTO villagers (id, 姓名, 性别, 公民身份证号码, 户籍地址, 与户主关系, 电话号码, 备注一, 备注二, tags, deleted_at) 
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`);
            for (let v of villagers) {
                const exist = db.prepare(`SELECT id FROM villagers WHERE 公民身份证号码 = ?`).get([v[4]]);
                if (exist) {
                    db.prepare(`UPDATE villagers SET 姓名=?, 性别=?, 户籍地址=?, 与户主关系=?, 电话号码=?, 备注一=?, 备注二=?, tags=? WHERE 公民身份证号码=?`)
                        .run([v[1], v[2], v[3], v[4], v[5], v[6], v[7], v[8], v[4]]);
                } else {
                    insertVillager.run(v);
                }
            }
            insertVillager.free();
            const insertPhoto = db.prepare(`INSERT OR IGNORE INTO villager_photos (id, villager_id, filename, filepath, description, image_data, created_at) 
                VALUES (?, ?, ?, ?, ?, ?, ?)`);
            for (let p of photos) { insertPhoto.run(p); }
            insertPhoto.free();
            const insertKinship = db.prepare(`INSERT OR IGNORE INTO kinship (id, person1_id, person2_id, relation, auto, created_at) 
                VALUES (?, ?, ?, ?, ?, ?)`);
            for (let k of kinship) { insertKinship.run(k); }
            insertKinship.free();
        });
    }
};

// ============================================================
// 3. 界面逻辑
// ============================================================
let villagers = [];
let currentVillagers = [];
let currentPage = 1;
let itemsPerPage = 20;
let selectedItems = new Set();
let isBatchMode = false;
let currentHouseholdAddress = '';
let currentSearchKeyword = '';
let currentAgeMin = null;
let currentAgeMax = null;
let hideDeceased = false;
let genderChart = null, ageChart = null, groupChart = null;

const tableBody = document.getElementById('table-body');
const dataCount = document.getElementById('data-count');
const pagination = document.getElementById('pagination');
const statsRow = document.getElementById('stats-row');
const tablePaginationTop = document.getElementById('table-pagination-top');
const editModal = document.getElementById('edit-modal');
const detailModal = document.getElementById('detail-modal');
const deleteModal = document.getElementById('delete-modal');
const groupStatsModal = document.getElementById('group-stats-modal');
const importModal = document.getElementById('import-modal');
const batchEditModal = document.getElementById('batch-edit-modal');
const chartModal = document.getElementById('chart-modal');
const advancedSearchModal = document.getElementById('advanced-search-modal');
const selectMemberModal = document.getElementById('select-member-modal');
const hideDeceasedCheckbox = document.getElementById('hideDeceasedCheckbox');

// 工具函数
function calculateAgeFromID(idCard) {
    if (!idCard || idCard.length !== 18) return 0;
    try {
        const birthYear = parseInt(idCard.substring(6,10));
        const birthMonth = parseInt(idCard.substring(10,12))-1;
        const birthDay = parseInt(idCard.substring(12,14));
        const birthDate = new Date(birthYear, birthMonth, birthDay);
        const today = new Date();
        let age = today.getFullYear() - birthDate.getFullYear();
        const monthDiff = today.getMonth() - birthDate.getMonth();
        if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) age--;
        return age >=0 ? age : 0;
    } catch(e) { return 0; }
}

function getHouseholdByAddress(villager) {
    const members = [];
    if (villager.与户主关系 === '独立') { members.push(villager); return members; }
    const address = villager.户籍地址;
    for (let v of villagers) {
        if (v.户籍地址 === address && v.与户主关系 !== '独立') members.push(v);
    }
    return members;
}

function countHouseholdMembers(index) {
    const villager = villagers[index];
    return getHouseholdByAddress(villager).length;
}

function sortByAddress(a, b) {
    function parseAddress(addr) {
        const mainMatch = addr.match(/湾泥[渡]?村(\d+)组(\d+)号/);
        if (!mainMatch) return { group: 99999, number: 99999, sub: 99999 };
        const group = parseInt(mainMatch[1]);
        const number = parseInt(mainMatch[2]);
        let sub = 0;
        const subMatch = addr.match(/附([一二三四五六七八九十\d]+)号/);
        if (subMatch) {
            const chnMap = { '一':1, '二':2, '三':3, '四':4, '五':5, '六':6, '七':7, '八':8, '九':9, '十':10 };
            sub = chnMap[subMatch[1]] || parseInt(subMatch[1]) || 0;
        }
        return { group, number, sub };
    }
    function rolePriority(relation) {
        const map = {
            '户主': 0, '妻': 1, '夫': 1,
            '子': 2, '女': 2, '儿媳': 2, '女婿': 2,
            '孙子': 3, '孙女': 3,
            '母亲': 4, '父亲': 4,
            '弟': 5, '妹': 5,
            '其他': 6, '独立': 7
        };
        return map[relation] !== undefined ? map[relation] : 6;
    }
    const addrA = parseAddress(a.户籍地址);
    const addrB = parseAddress(b.户籍地址);
    if (addrA.group !== addrB.group) return addrA.group - addrB.group;
    if (addrA.number !== addrB.number) return addrA.number - addrB.number;
    if (addrA.sub !== addrB.sub) return addrA.sub - addrB.sub;
    return rolePriority(a.与户主关系) - rolePriority(b.与户主关系);
}

function validateID(id) { return /^\d{17}[\dX]$/i.test(id); }

// 加载数据（应用所有过滤条件）
function loadVillagers() {
    let raw = localDB.getVillagers() || [];
    raw.sort(sortByAddress);
    // 隐藏死亡人员
    if (hideDeceased) {
        raw = raw.filter(v => {
            const d1 = v.备注一 && v.备注一.includes('死亡');
            const d2 = v.备注二 && v.备注二.includes('死亡');
            return !d1 && !d2;
        });
    }
    // 标签过滤
    if (currentSearchKeyword) {
        const keyword = currentSearchKeyword.toLowerCase();
        raw = raw.filter(v => Object.values(v).some(f => String(f).toLowerCase().includes(keyword)));
    }
    // 年龄过滤
    if (currentAgeMin !== null || currentAgeMax !== null) {
        raw = raw.filter(v => {
            const age = calculateAgeFromID(v.公民身份证号码);
            if (currentAgeMin !== null && age < currentAgeMin) return false;
            if (currentAgeMax !== null && age > currentAgeMax) return false;
            return true;
        });
    }
    villagers = raw;
    currentVillagers = [...villagers];
    currentPage = 1;
    renderTable();
    updateStats();
}

function renderTable() {
    const totalItems = currentVillagers.length;
    const totalPages = Math.ceil(totalItems / itemsPerPage) || 1;
    if (currentPage > totalPages) currentPage = totalPages;
    if (currentPage < 1) currentPage = 1;
    const startIndex = (currentPage-1)*itemsPerPage;
    const endIndex = Math.min(startIndex+itemsPerPage, totalItems);
    const pageData = currentVillagers.slice(startIndex, endIndex);
    tableBody.innerHTML = '';
    pageData.forEach((villager, idx) => {
        const row = document.createElement('tr');
        const isDeceased = (villager.备注一 && villager.备注一.includes('死亡')) || (villager.备注二 && villager.备注二.includes('死亡'));
        const isNoHousehold = villager.与户主关系 === '独立';
        if (isDeceased) row.classList.add('deceased');
        else if (isNoHousehold) row.classList.add('no-household');
        const age = calculateAgeFromID(villager.公民身份证号码);
        let householdBadge = '';
        if (villager.与户主关系 === '户主') {
            const fullIndex = villagers.findIndex(v => v.公民身份证号码 === villager.公民身份证号码);
            if (fullIndex !== -1) householdBadge = `<span class="household-badge">${countHouseholdMembers(fullIndex)}人</span>`;
        } else if (isNoHousehold) householdBadge = `<span class="household-badge" style="background-color:#fff3cd;color:#856404;">无户</span>`;
        let phoneDisplay = villager.电话号码 || '';
        if (phoneDisplay && /^1[3-9]\d{9}$/.test(phoneDisplay)) phoneDisplay = `<a href="tel:${phoneDisplay}" class="phone-link">${phoneDisplay}</a>`;
        const checkboxHtml = isBatchMode ? `<input type="checkbox" class="row-checkbox" data-index="${startIndex+idx}">` : '';
        row.innerHTML = `<td class="table-checkbox-column">${checkboxHtml}</td><td>${villager.姓名}</td><td>${villager.性别}</td><td class="age-column">${age>0?age:''}</td><td>${villager.户籍地址}</td><td>${villager.与户主关系} ${householdBadge}</td><td>${phoneDisplay}</td><td class="actions-cell"><button class="btn-info view-btn" data-id="${villager.id}"><i class="fas fa-eye"></i> 查看</button><button class="btn-primary edit-btn" data-id="${villager.id}"><i class="fas fa-edit"></i> 编辑</button></td>`;
        tableBody.appendChild(row);
    });
    dataCount.textContent = `找到 ${totalItems} 条记录${totalPages>1 ? `，当前显示第 ${currentPage} 页` : ''}`;
    renderPagination(totalPages, 'top');
    renderPagination(totalPages, 'bottom');
    document.querySelectorAll('.view-btn').forEach(btn => btn.addEventListener('click', () => openDetailModal(parseInt(btn.dataset.id))));
    document.querySelectorAll('.edit-btn').forEach(btn => btn.addEventListener('click', () => openEditModal(parseInt(btn.dataset.id))));
    if (isBatchMode) {
        document.querySelectorAll('.row-checkbox').forEach(cb => cb.addEventListener('change', function() {
            const idx = parseInt(this.dataset.index);
            if (this.checked) selectedItems.add(idx); else selectedItems.delete(idx);
            updateSelectedCount();
        }));
    }
    updateBatchDeleteButton();
}

function renderPagination(totalPages, position) {
    let container = position==='top' ? tablePaginationTop : pagination;
    container.innerHTML = '';
    if (totalPages<=1) { if(position==='top') container.innerHTML='<div class="group-summary">共1页</div>'; return; }
    const nav = document.createElement('div'); nav.className='pagination-nav';
    const firstBtn = document.createElement('button'); firstBtn.className=`page-btn ${currentPage===1?'disabled':''}`; firstBtn.innerHTML='&laquo;'; firstBtn.disabled=currentPage===1; firstBtn.onclick=()=>{if(currentPage>1){currentPage=1;renderTable();}}; nav.appendChild(firstBtn);
    const prevBtn = document.createElement('button'); prevBtn.className=`page-btn ${currentPage===1?'disabled':''}`; prevBtn.innerHTML='&lsaquo;'; prevBtn.disabled=currentPage===1; prevBtn.onclick=()=>{if(currentPage>1){currentPage--;renderTable();}}; nav.appendChild(prevBtn);
    let startPage = Math.max(1, currentPage-2), endPage = Math.min(totalPages, currentPage+2);
    for(let i=startPage; i<=endPage; i++) {
        const pgBtn = document.createElement('button'); pgBtn.className=`page-btn ${i===currentPage?'active':''}`; pgBtn.textContent=i; pgBtn.onclick=()=>{currentPage=i;renderTable();}; nav.appendChild(pgBtn);
    }
    const nextBtn = document.createElement('button'); nextBtn.className=`page-btn ${currentPage===totalPages?'disabled':''}`; nextBtn.innerHTML='&rsaquo;'; nextBtn.disabled=currentPage===totalPages; nextBtn.onclick=()=>{if(currentPage<totalPages){currentPage++;renderTable();}}; nav.appendChild(nextBtn);
    const lastBtn = document.createElement('button'); lastBtn.className=`page-btn ${currentPage===totalPages?'disabled':''}`; lastBtn.innerHTML='&raquo;'; lastBtn.disabled=currentPage===totalPages; lastBtn.onclick=()=>{if(currentPage<totalPages){currentPage=totalPages;renderTable();}}; nav.appendChild(lastBtn);
    container.appendChild(nav);
    if(position==='top') { let info=document.createElement('div'); info.className='group-summary'; info.textContent=`第 ${currentPage} 页 / 共 ${totalPages} 页`; container.appendChild(info); }
}

function updateStats() {
    let householdCount = villagers.filter(v=>v.与户主关系==='户主').length;
    let totalCount = villagers.filter(v=>!(v.备注一&&v.备注一.includes('死亡')||v.备注二&&v.备注二.includes('死亡'))).length;
    let maleCount = villagers.filter(v=>v.性别==='男').length;
    let femaleCount = villagers.length - maleCount;
    let groupSet = new Set();
    villagers.forEach(v=>{ let m=v.户籍地址.match(/湾泥[渡]?村\s*(\d+)\s*组/); groupSet.add(m?m[1]:'其他'); });
    let groupCount = groupSet.size;
    let deceasedCount = villagers.filter(v=>v.备注一?.includes('死亡')||v.备注二?.includes('死亡')).length;
    let noHouseholdCount = villagers.filter(v=>v.与户主关系==='独立').length;
    statsRow.innerHTML = `<div class="stat-item"><div class="stat-value">${groupCount}</div><div class="stat-label">总组数</div></div><div class="stat-item"><div class="stat-value">${householdCount}</div><div class="stat-label">总户数</div></div><div class="stat-item"><div class="stat-value">${totalCount}</div><div class="stat-label">总人数</div></div><div class="stat-item"><div class="stat-value">${maleCount}</div><div class="stat-label">男性</div></div><div class="stat-item"><div class="stat-value">${femaleCount}</div><div class="stat-label">女性</div></div><div class="stat-item"><div class="stat-value">${deceasedCount}</div><div class="stat-label">死亡</div></div><div class="stat-item"><div class="stat-value">${noHouseholdCount}</div><div class="stat-label">无户</div></div>`;
}

