// ===== 照片 =====
async function loadPhotos(villagerId) {
    const container = document.getElementById(`photo-list-${villagerId}`);
    if (!container) return;
    const photos = localDB.getPhotos(villagerId);
    if (photos.length === 0) { container.innerHTML = '<p style="color:#999;">暂无证件照片</p>'; return; }
    let html = '';
    for (let photo of photos) {
        const imgSrc = photo.image_data ? `data:image/jpeg;base64,${photo.image_data}` : '';
        html += `
            <div style="border:1px solid #ddd; border-radius:8px; padding:5px; width:120px; text-align:center;">
                ${imgSrc ? `<img src="${imgSrc}" style="width:100px; height:100px; object-fit:cover; cursor:pointer;" onclick="window.open('${imgSrc}')" alt="证件照">` : '<div style="width:100px;height:100px;background:#eee;">无图片</div>'}
                <div style="font-size:12px; margin-top:5px;">
                    <span class="editable-desc" data-id="${photo.id}" data-villager="${villagerId}" contenteditable="true" style="display:inline-block; min-width:60px; border-bottom:1px dashed #ccc; cursor:text;">${photo.description || '无描述'}</span>
                </div>
                <button class="btn-danger btn-sm" style="font-size:10px; padding:2px 6px; margin-top:4px;" onclick="deletePhoto(${photo.id}, ${villagerId})">删除</button>
            </div>
        `;
    }
    container.innerHTML = html;
    document.querySelectorAll('.editable-desc').forEach(elem => {
        const photoId = elem.dataset.id;
        const villagerId = elem.dataset.villager;
        let oldValue = elem.innerText;
        elem.addEventListener('blur', () => {
            const newValue = elem.innerText.trim();
            if (newValue !== oldValue) {
                localDB.updatePhotoDescription(parseInt(photoId), newValue);
                oldValue = newValue;
            }
        });
        elem.addEventListener('keypress', (e) => { if (e.key === 'Enter') { e.preventDefault(); elem.blur(); } });
    });
}
async function uploadPhoto(villagerId) {
    const fileInput = document.getElementById(`photo-input-${villagerId}`);
    const file = fileInput.files[0];
    if (!file) { alert('请选择图片'); return; }
    const reader = new FileReader();
    reader.onload = function(e) {
        const base64 = e.target.result.split(',')[1];
        localDB.addPhoto(villagerId, file.name, base64, '');
        fileInput.value = '';
        loadPhotos(villagerId);
    };
    reader.readAsDataURL(file);
}
async function deletePhoto(photoId, villagerId) {
    if (!confirm('确定删除这张照片吗？')) return;
    localDB.deletePhoto(photoId);
    loadPhotos(villagerId);
}

// ===== 亲属关系 =====
async function loadKinship(villagerId) {
    const container = document.getElementById(`kinship-list-${villagerId}`);
    if (!container) return;
    const data = localDB.getKinship(villagerId);
    if (data.length === 0) { container.innerHTML = '<p style="color:#999;">暂无亲属关系</p>'; return; }
    const groups = {};
    for (let item of data) {
        const rel = item.relation || '其他';
        if (!groups[rel]) groups[rel] = [];
        groups[rel].push(item);
    }
    let html = '<div style="display:flex; flex-direction:column; gap:5px;">';
    for (let [rel, list] of Object.entries(groups)) {
        html += `<div><strong>${rel}：</strong>`;
        html += list.map(p => {
            let delBtn = `<button class="btn-sm" style="font-size:11px; padding:2px 8px; border-radius:20px; border:1px solid #dc3545; background:white; color:#dc3545; margin-left:6px; cursor:pointer;" onclick="deleteKinship(${p.relation_id}, ${villagerId})">移除</button>`;
            return `<span style="background:#f0f2f5; padding:5px 12px; border-radius:30px; display:inline-flex; align-items:center; margin-right:5px; margin-bottom:5px;"><a href="#" onclick="event.preventDefault(); openDetailModal(${p.id})">${p.name}</a>${delBtn}</span>`;
        }).join('');
        html += '</div>';
    }
    container.innerHTML = html;
}
async function deleteKinship(relationId, villagerId) {
    if (!confirm('确定删除这条亲属关系吗？')) return;
    localDB.deleteKinship(relationId);
    loadKinship(villagerId);
}
function openAddKinshipModal(villagerId) {
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:2000;display:flex;align-items:center;justify-content:center;';
    const modal = document.createElement('div');
    modal.style.cssText = 'background:white;padding:20px;border-radius:12px;width:350px;max-width:90%;';
    const datalistId = `rel-${Date.now()}`;
    const options = villagers.filter(v => v.id !== villagerId).map(v => `<option value="${v.姓名}">${v.姓名}</option>`).join('');
    modal.innerHTML = `
        <h3>添加亲属关系</h3>
        <div style="margin:15px 0;"><label>关系类型</label><select id="rel-type" style="width:100%;padding:8px;">
            <option value="父亲">父亲</option><option value="母亲">母亲</option>
            <option value="丈夫">丈夫</option><option value="妻子">妻子</option>
            <option value="儿子">儿子</option><option value="儿媳">儿媳</option>
            <option value="女儿">女儿</option>
            <option value="哥哥">哥哥</option><option value="弟弟">弟弟</option>
            <option value="姐姐">姐姐</option><option value="妹妹">妹妹</option>
            <option value="爷爷">爷爷</option><option value="奶奶">奶奶</option>
            <option value="孙子">孙子</option><option value="孙女">孙女</option>
        </select></div>
        <div style="margin:15px 0;"><label>对方姓名</label><input type="text" id="rel-other-input" list="${datalistId}" style="width:100%;padding:8px;" placeholder="输入姓名"><datalist id="${datalistId}">${options}</datalist></div>
        <div style="display:flex;gap:10px;justify-content:flex-end;"><button id="cancel-rel" class="btn-secondary">取消</button><button id="save-rel" class="btn-primary">保存</button></div>
    `;
    overlay.appendChild(modal);
    document.body.appendChild(overlay);
    document.getElementById('cancel-rel').onclick = () => overlay.remove();
    document.getElementById('save-rel').onclick = () => {
        const relation = document.getElementById('rel-type').value;
        const otherName = document.getElementById('rel-other-input').value.trim();
        const other = villagers.find(v => v.姓名 === otherName && v.id !== villagerId);
        if (!other) { alert('未找到该村民'); return; }
        try { localDB.addKinship(villagerId, other.id, relation); overlay.remove(); loadKinship(villagerId); } catch(e) { alert(e.message); }
    };
}

