function openSelectMemberModal() {
    const available = villagers.filter(v => v.与户主关系 === '独立' && v.户籍地址 !== currentHouseholdAddress);
    let html = available.length === 0 ? '<p>暂无可用村民</p>' :
        available.map(m => `<div class="household-member-item"><div><strong>${m.姓名}</strong> <span class="family-relationship">(${m.与户主关系})</span> ${calculateAgeFromID(m.公民身份证号码)||''}</div><div class="member-actions"><button class="btn-success btn-sm add-existing-member" data-id="${m.公民身份证号码}">加入本户</button></div></div>`).join('');
    document.getElementById('available-members-list').innerHTML = html;
    document.querySelectorAll('.add-existing-member').forEach(btn => btn.addEventListener('click', () => addExistingMemberToHousehold(btn.dataset.id)));
    selectMemberModal.style.display = 'block';
}
