// ===== 各组统计 =====
document.getElementById('group-stats-btn').addEventListener('click', function() {
    const groupStats = {};
    villagers.forEach(v => {
        let groupNum = '其他';
        const m = v.户籍地址.match(/湾泥[渡]?村\s*(\d+)\s*组/);
        if(m && m[1]) groupNum = m[1];
        if(!groupStats[groupNum]) groupStats[groupNum] = { households: new Set(), members:0, males:0, females:0, deceased:0 };
        groupStats[groupNum].members++;
        if(v.性别==='男') groupStats[groupNum].males++; else groupStats[groupNum].females++;
        if((v.备注一 && v.备注一.includes('死亡')) || (v.备注二 && v.备注二.includes('死亡'))) groupStats[groupNum].deceased++;
        if(v.与户主关系 === '户主') groupStats[groupNum].households.add(v.户籍地址);
    });
    let statsHTML = `<table class="group-stats-table"><thead><tr><th style="background:#4a6fa5;color:white;">组号</th><th style="background:#4a6fa5;color:white;">户数</th><th style="background:#4a6fa5;color:white;">总人数</th><th style="background:#4a6fa5;color:white;">男性</th><th style="background:#4a6fa5;color:white;">女性</th><th style="background:#4a6fa5;color:white;">死亡</th></tr></thead><tbody>`;
    const sortedGroups = Object.keys(groupStats).sort((a,b)=>{ if(a==='其他') return 1; if(b==='其他') return -1; return parseInt(a)-parseInt(b); });
    sortedGroups.forEach(g => { const s = groupStats[g]; statsHTML += `<tr><td>${g==='其他'?'其他':g+'组'}</td><td>${s.households.size}</td><td>${s.members}</td><td>${s.males}</td><td>${s.females}</td><td>${s.deceased}</td></tr>`; });
    let totalHouseholds=0, totalMembers=0, totalMales=0, totalFemales=0, totalDeceased=0;
    sortedGroups.forEach(g => { const s = groupStats[g]; totalHouseholds += s.households.size; totalMembers += s.members; totalMales += s.males; totalFemales += s.females; totalDeceased += s.deceased; });
    statsHTML += `<tr style="font-weight: bold; background-color: #f0f8ff;"><td>总计</td><td>${totalHouseholds}</td><td>${totalMembers}</td><td>${totalMales}</td><td>${totalFemales}</td><td>${totalDeceased}</td></tr></tbody></table>`;
    document.getElementById('group-stats-content').innerHTML = statsHTML;
    groupStatsModal.style.display = 'block';
});
document.getElementById('close-group-stats').addEventListener('click', () => groupStatsModal.style.display = 'none');

// ===== 图表 =====
document.getElementById('chart-btn').addEventListener('click', () => {
    chartModal.style.display = 'block';
    setTimeout(createCharts, 100);
});
document.getElementById('close-chart').addEventListener('click', () => {
    chartModal.style.display = 'none';
    if (genderChart) genderChart.destroy();
    if (ageChart) ageChart.destroy();
    if (groupChart) groupChart.destroy();
});
function createCharts() {
    const maleCount = villagers.filter(v=>v.性别==='男').length;
    const femaleCount = villagers.filter(v=>v.性别==='女').length;
    const genderCtx = document.getElementById('gender-chart').getContext('2d');
    if(genderChart) genderChart.destroy();
    genderChart = new Chart(genderCtx, { type:'pie', data:{ labels:['男性','女性'], datasets:[{ data:[maleCount,femaleCount], backgroundColor:['#4a6fa5','#e83e8c'] }] }, options:{ responsive:true, plugins:{ legend:{ position:'bottom' }, title:{ display:true, text:`总人数: ${villagers.length}` } } } });
    const ageGroups = { '0-17岁':0, '18-35岁':0, '36-59岁':0, '60岁以上':0 };
    villagers.forEach(v => { const a = calculateAgeFromID(v.公民身份证号码); if(a>0){ if(a<=17) ageGroups['0-17岁']++; else if(a<=35) ageGroups['18-35岁']++; else if(a<=59) ageGroups['36-59岁']++; else ageGroups['60岁以上']++; } });
    const ageCtx = document.getElementById('age-chart').getContext('2d');
    if(ageChart) ageChart.destroy();
    ageChart = new Chart(ageCtx, { type:'bar', data:{ labels:Object.keys(ageGroups), datasets:[{ label:'人数', data:Object.values(ageGroups), backgroundColor:'#28a745', borderColor:'#1e7e34', borderWidth:1 }] }, options:{ responsive:true, scales:{ y:{ beginAtZero:true, ticks:{ stepSize:1 } } } } });
    const groupData = {};
    villagers.forEach(v => { let groupNum='其他'; const m=v.户籍地址.match(/湾泥[渡]?村\s*(\d+)\s*组/); if(m&&m[1]) groupNum=m[1]; groupData[groupNum]=(groupData[groupNum]||0)+1; });
    const sortedGroups = Object.keys(groupData).sort((a,b)=>{ if(a==='其他') return 1; if(b==='其他') return -1; return parseInt(a)-parseInt(b); });
    const groupLabels = sortedGroups.map(g=>g==='其他'?'其他':`${g}组`);
    const groupValues = sortedGroups.map(g=>groupData[g]);
    const groupCtx = document.getElementById('group-chart').getContext('2d');
    if(groupChart) groupChart.destroy();
    groupChart = new Chart(groupCtx, { type:'line', data:{ labels:groupLabels, datasets:[{ label:'人口数', data:groupValues, backgroundColor:'rgba(255,193,7,0.2)', borderColor:'#ffc107', borderWidth:2, fill:true, tension:0.4 }] }, options:{ responsive:true, scales:{ y:{ beginAtZero:true, ticks:{ stepSize:1 } } } } });
}

