document.getElementById('apply-batch-edit').addEventListener('click', async function() {
    const field = document.getElementById('batch-field').value;
    const value = document.getElementById('batch-value').value.trim();
    if (!field) { alert('请选择字段'); return; }
    if (!value && field !== '备注一' && field !== '备注二') { alert('请输入新值'); return; }
    if (!confirm(`确定将选中的 ${selectedItems.size} 条记录的"${field}"修改为"${value}"吗？`)) return;
    const ids = Array.from(selectedItems).map(i => currentVillagers[i].id);
    for (let id of ids) {
        const v = villagers.find(v => v.id === id);
        if (!v) continue;
        if (field === '户籍地址') {
            if (!value.includes('湾泥渡村') && !value.includes('湾泥村')) v[field] = `湾泥村${value}`;
            else v[field] = value;
        } else {
            v[field] = value;
        }
        localDB.updateVillager(id, v);
    }
    loadVillagers();
    cancelBatchMode();
    alert(`修改了 ${ids.length} 条记录`);
});
