document.getElementById('start-import').addEventListener('click', function() {
    const fileInput = document.getElementById('import-file');
    const file = fileInput.files[0];
    if (!file) { alert('请选择文件'); return; }
    const mode = document.querySelector('input[name="import-mode"]:checked').value;
    const reader = new FileReader();
    reader.onload = function(e) {
        try {
            const data = JSON.parse(e.target.result);
            if (!data.data || !data.data.villagers) { alert('无效的数据文件'); return; }
            if (mode === 'replace' && !confirm('替换模式将清除所有现有数据，确定继续吗？')) return;
            localDB.importData(data.data, mode);
            loadVillagers();
            alert('导入成功！');
            importModal.style.display = 'none';
        } catch(err) {
            alert('导入失败：' + err.message);
        }
    };
    reader.readAsText(file);
});

