function copyText(text) {
    if (navigator.clipboard) {
        navigator.clipboard.writeText(text).then(() => showCopyTip('已复制：' + text)).catch(() => fallbackCopy(text));
    } else { fallbackCopy(text); }
}
function fallbackCopy(text) {
    const input = document.createElement('input');
    input.value = text;
    input.style.position = 'fixed';
    input.style.left = '-9999px';
    input.style.top = '0';
    document.body.appendChild(input);
    input.select();
    try { document.execCommand('copy'); showCopyTip('已复制：' + text); } catch(e) { alert('复制失败'); }
    document.body.removeChild(input);
}
function showCopyTip(msg) {
    const tip = document.createElement('div');
    tip.textContent = msg;
    tip.style.cssText = `position:fixed;bottom:30px;left:50%;transform:translateX(-50%);background:#4a6fa5;color:#fff;padding:8px 24px;border-radius:20px;font-size:14px;z-index:9999;box-shadow:0 4px 16px rgba(0,0,0,0.2);opacity:0;transition:opacity 0.3s;`;
    document.body.appendChild(tip);
    setTimeout(() => tip.style.opacity = '1', 10);
    setTimeout(() => { tip.style.opacity = '0'; setTimeout(() => tip.remove(), 300); }, 2000);
}

